CREATE TABLE images (id INTEGER PRIMARY KEY AUTOINCREMENT , hash TEXT NOT NULL UNIQUE , name TEXT NOT NULL , is_favorite INTEGER DEFAULT 0, added_at DATETIME DEFAULT CURRENT_TIMESTAMP , updated_at DATETIME DEFAULT CURRENT_TIMESTAMP , info TEXT );
CREATE TABLE tags (id INTEGER PRIMARY KEY , technical_name TEXT NOT NULL );
CREATE TABLE categories (id INTEGER PRIMARY KEY , display_name TEXT NOT NULL , technical_name TEXT NOT NULL );
CREATE TABLE images_tags (id INTEGER PRIMARY KEY , image_id TEXT NOT NULL , tag_id INTEGER NOT NULL , FOREIGN KEY(image_id) REFERENCES images(id) ON DELETE CASCADE , FOREIGN KEY(tag_id) REFERENCES tags(id) ON DELETE CASCADE );
CREATE TABLE images_categories (id INTEGER PRIMARY KEY , image_id TEXT NOT NULL , category_id INTEGER NOT NULL , FOREIGN KEY(image_id) REFERENCES images(id) ON DELETE CASCADE , FOREIGN KEY(category_id) REFERENCES categories(id) ON DELETE CASCADE );
CREATE TABLE excalidraw_scenes (uuid TEXT PRIMARY KEY , name TEXT NOT NULL , created_at DATETIME DEFAULT CURRENT_TIMESTAMP , updated_at DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE migrations (id INTEGER PRIMARY KEY AUTOINCREMENT , name TEXT NOT NULL UNIQUE , executed_at DATETIME DEFAULT CURRENT_TIMESTAMP );